"use client";

import { motion } from "framer-motion";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import { Shield } from "lucide-react";

export default function PrivacyPolicy() {
    return (
        <div className="min-h-screen bg-background text-foreground overflow-hidden">

            {/* Hero Section */}
            <section className="relative pt-32 pb-20 px-4 overflow-hidden">
                <div className="absolute inset-0 bg-cosmic-900/20 z-0 pointer-events-none" />
                <div className="container mx-auto relative z-10 grid lg:grid-cols-2 gap-12 items-center">

                    <motion.div
                        initial={{ opacity: 0, x: -50 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.8 }}
                    >
                        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 text-primary border border-primary/20 text-xs font-bold uppercase tracking-wider mb-6">
                            <span className="w-2 h-2 rounded-full bg-primary animate-pulse" />
                            Legal Framework
                        </div>
                        <h1 className="text-5xl md:text-7xl font-black mb-6 tracking-tight leading-tight">
                            Privacy <br />
                            <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-cosmic-purple">
                                Protocol
                            </span>
                        </h1>
                        <p className="text-xl text-muted-foreground/80 font-medium leading-relaxed max-w-lg">
                            Your data sovereignty is our priority. We use advanced encryption and minimal data collection to ensure your voice is heard without compromising your identity.
                        </p>
                    </motion.div>

                    <motion.div
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: 1, scale: 1 }}
                        transition={{ duration: 1 }}
                        className="h-[400px] lg:h-[500px] w-full relative flex items-center justify-center"
                    >
                        {/* CSS-based Security Visual */}
                        <div className="relative w-full h-full flex items-center justify-center">
                            <div className="absolute inset-0 bg-gradient-to-tr from-primary/10 to-transparent rounded-full blur-3xl animate-pulse-glow" />

                            <div className="relative w-72 h-72">
                                {/* Shield and Lock Visual */}
                                <div className="absolute inset-0 rounded-full bg-gradient-to-br from-primary/10 to-cosmic-purple/10 backdrop-blur-3xl border border-white/5 flex items-center justify-center">
                                    <div className="relative">
                                        <Shield className="w-24 h-24 text-primary opacity-50 absolute -inset-4 blur-sm" />
                                        <Shield className="w-24 h-24 text-primary relative z-10" />
                                    </div>
                                </div>

                                {/* Orbiting Security Rings */}
                                {/* Replaced static CSS animation with Framer Motion for the rings */}
                                <motion.div
                                    animate={{ rotate: 360 }}
                                    transition={{
                                        duration: 10, // Base duration
                                        repeat: Infinity,
                                        ease: "linear"
                                    }}
                                    className="absolute inset-0 border border-primary/20 rounded-full"
                                />
                                <motion.div
                                    animate={{ rotate: -360 }} // Reverse spin
                                    transition={{
                                        duration: 15, // Different duration
                                        repeat: Infinity,
                                        ease: "linear"
                                    }}
                                    className="absolute inset-10 border border-cosmic-purple/20 rounded-full"
                                />
                            </div>
                        </div>
                    </motion.div>
                </div>
            </section>

            {/* Content Section */}
            <section className="container mx-auto px-4 py-20 max-w-4xl">
                <div className="space-y-12">

                    <PolicySection title="1. Information Collection">
                        We collect information to facilitate the PIL process. This includes your name, email (for authentication), and IP address (for security and abuse prevention). We do not sell your personal data to third parties.
                    </PolicySection>

                    <PolicySection title="2. Public Visibility">
                        Petitions (PILs) filed on JanVichar are public documents. Your name as the creator will be visible to support transparency in public interest litigations.
                    </PolicySection>

                    <PolicySection title="3. Data Security">
                        We employ industry-standard encryption (SSL/TLS) for data in transit. Our database is secured with strict access controls. Only authorized administrators can access sensitive user logs.
                    </PolicySection>

                    <PolicySection title="4. Cookies & Tracking">
                        We use local storage and cookies solely for maintaining your session and preferences (like Dark Mode). We use a custom lightweight tracking system to monitor platform usage and prevent bot activity.
                    </PolicySection>

                    <div className="pt-10 border-t border-border">
                        <p className="text-sm text-muted-foreground text-center">
                            Last Updated: October 25, 2026 • Effective Date: Immediate
                        </p>
                    </div>

                </div>
            </section>
        </div>
    );
}

function PolicySection({ title, children }: { title: string, children: React.ReactNode }) {
    return (
        <motion.div
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="bg-card/50 backdrop-blur-sm border border-white/5 p-8 rounded-3xl hover:bg-card/80 transition-all cursor-default"
        >
            <h2 className="text-2xl font-bold mb-4 text-primary">{title}</h2>
            <p className="text-muted-foreground leading-relaxed font-medium">
                {children}
            </p>
        </motion.div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useAuth } from "@/context/AuthContext";
import { useLanguage } from "@/context/LanguageContext";
import { db } from "@/lib/firebase";
import { collection, query, where, getDocs, doc, getDoc, setDoc, serverTimestamp } from "firebase/firestore";
import {
    User,
    Mail,
    Phone,
    Save,
    FileText,
    Clock,
    CheckCircle2,
    AlertCircle,
    ChevronRight,
    Loader2,
    Settings,
    ShieldCheck,
    Activity,
    PlusCircle,
    ThumbsUp,
    Calendar,
    PieChart
} from "lucide-react";
import { cn } from "@/lib/utils";
import { motion } from "framer-motion";
import Link from "next/link";

interface UserProfile {
    name: string;
    email: string;
    phone: string;
    bio: string;
}

interface UserPIL {
    id: string;
    title: string;
    status: string;
    createdAt: { seconds: number; nanoseconds: number } | null;
    supporters: number;
}

export default function ProfilePage() {
    const { user, login } = useAuth();
    const { t } = useLanguage();
    const [profile, setProfile] = useState<UserProfile>({
        name: "",
        email: "",
        phone: "",
        bio: ""
    });
    const [myPils, setMyPils] = useState<UserPIL[]>([]);
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState<{ type: "success" | "error", text: string } | null>(null);

    useEffect(() => {
        if (!user) return;

        const fetchProfileAndPils = async () => {
            setLoading(true);
            try {
                // Fetch Profile
                const profileDoc = await getDoc(doc(db, "profiles", user.uid));
                if (profileDoc.exists()) {
                    setProfile(profileDoc.data() as UserProfile);
                } else {
                    setProfile({
                        name: user.displayName || "",
                        email: user.email || "",
                        phone: "",
                        bio: ""
                    });
                }

                // Fetch My PILs
                const pilsQuery = query(collection(db, "pils"), where("createdBy", "==", user.uid));
                const pilsSnapshot = await getDocs(pilsQuery);
                const pilsData = pilsSnapshot.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data()
                })) as UserPIL[];

                // Sort by date
                pilsData.sort((a, b) => (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0));
                setMyPils(pilsData);
            } catch (error) {
                console.error("Error fetching profile data:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchProfileAndPils();
    }, [user]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;

        setSaving(true);
        setMessage(null);
        try {
            await setDoc(doc(db, "profiles", user.uid), {
                ...profile,
                updatedAt: serverTimestamp()
            }, { merge: true });
            setMessage({ type: "success", text: "Profile updated successfully!" });
        } catch (error) {
            console.error("Error saving profile:", error);
            setMessage({ type: "error", text: "Failed to update profile." });
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[70vh]">
                <Loader2 className="w-10 h-10 text-primary animate-spin mb-4" />
                <p className="text-muted-foreground animate-pulse">Loading dashboard...</p>
            </div>
        );
    }

    if (!user) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[70vh] px-4 text-center">
                <AlertCircle size={48} className="text-muted-foreground mb-4" />
                <h1 className="text-2xl font-bold mb-2">Login Required</h1>
                <p className="text-muted-foreground mb-6">Please sign in to view your profile and tracking dashboard.</p>
                <button
                    onClick={login}
                    className="bg-primary text-white px-8 py-3 rounded-xl font-bold hover:shadow-xl transition-all active:scale-95"
                >
                    {t("nav.login")}
                </button>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-muted/20">
            {/* Profile Hero Header */}
            <div className="bg-primary pt-24 pb-32 px-4">
                <div className="container mx-auto max-w-6xl">
                    <div className="flex flex-col md:flex-row items-center gap-8 text-white">
                        <motion.div
                            initial={{ scale: 0.8, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            className="relative"
                        >
                            <div className="w-32 h-32 rounded-3xl bg-white/10 backdrop-blur-xl border-4 border-white/20 flex items-center justify-center shadow-2xl relative z-10 overflow-hidden">
                                {user.photoURL ? (
                                    <img src={user.photoURL} alt={profile.name} className="w-full h-full object-cover" />
                                ) : (
                                    <User size={64} className="text-white/40" />
                                )}
                            </div>
                            <div className="absolute -bottom-2 -right-2 bg-secondary text-white p-2 rounded-xl shadow-lg z-20">
                                <ShieldCheck size={20} />
                            </div>
                        </motion.div>
                        <div className="text-center md:text-left space-y-2">
                            <motion.div
                                initial={{ opacity: 0, x: -20 }}
                                animate={{ opacity: 1, x: 0 }}
                            >
                                <h1 className="text-4xl md:text-5xl font-black tracking-tight">{profile.name || user.displayName || "Anonymous"}</h1>
                                <p className="text-indigo-100/70 font-medium flex items-center justify-center md:justify-start gap-2">
                                    <Mail size={16} /> {user.email}
                                </p>
                            </motion.div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 -mt-20 pb-20 max-w-6xl">
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* Left Sidebar: Stats & Info */}
                    <div className="lg:col-span-4 space-y-6">
                        {/* Stats Card */}
                        <motion.div
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            className="bg-card border border-border rounded-3xl p-6 shadow-xl"
                        >
                            <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-6 pb-2 border-b border-border/50">
                                {t("profile.stats_title")}
                            </h3>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="bg-muted p-4 rounded-2xl">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase mb-1">Total PILs</p>
                                    <p className="text-2xl font-black text-primary">{myPils.length}</p>
                                </div>
                                <div className="bg-muted p-4 rounded-2xl">
                                    <p className="text-[10px] font-bold text-muted-foreground uppercase mb-1">Supported</p>
                                    <p className="text-2xl font-black text-secondary">
                                        {myPils.reduce((acc, curr) => acc + (curr.supporters || 0), 0)}
                                    </p>
                                </div>
                            </div>
                        </motion.div>

                        {/* Settings Form Card */}
                        <motion.section
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            className="bg-card border border-border rounded-3xl p-6 shadow-xl space-y-6"
                        >
                            <div className="flex items-center justify-between">
                                <h2 className="text-xl font-bold flex items-center gap-2">
                                    <Settings className="text-primary" size={20} />
                                    {t("nav.profile")}
                                </h2>
                            </div>

                            <form onSubmit={handleSave} className="space-y-4">
                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-muted-foreground flex items-center gap-2">
                                        <User size={12} /> {t("profile.name")}
                                    </label>
                                    <input
                                        type="text"
                                        value={profile.name}
                                        onChange={(e) => setProfile({ ...profile, name: e.target.value })}
                                        className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2.5 text-sm font-medium focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                        placeholder="Full Name"
                                    />
                                </div>

                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-muted-foreground flex items-center gap-2">
                                        <Phone size={12} /> {t("profile.phone")}
                                    </label>
                                    <input
                                        type="tel"
                                        value={profile.phone}
                                        onChange={(e) => setProfile({ ...profile, phone: e.target.value })}
                                        className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2.5 text-sm font-medium focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                                        placeholder="+91 XXXXX XXXXX"
                                    />
                                </div>

                                <div className="space-y-1.5">
                                    <label className="text-xs font-bold text-muted-foreground flex items-center gap-2">
                                        <FileText size={12} /> {t("profile.bio")}
                                    </label>
                                    <textarea
                                        value={profile.bio}
                                        onChange={(e) => setProfile({ ...profile, bio: e.target.value })}
                                        className="w-full bg-muted/50 border border-border rounded-xl px-4 py-2.5 text-sm font-medium focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all resize-none"
                                        placeholder={t("profile.bio")}
                                        rows={3}
                                    />
                                </div>

                                {message && (
                                    <motion.div
                                        initial={{ opacity: 0, height: 0 }}
                                        animate={{ opacity: 1, height: "auto" }}
                                        className={cn(
                                            "p-3 rounded-xl text-xs font-bold flex items-center gap-2",
                                            message.type === "success" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" : "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
                                        )}
                                    >
                                        {message.type === "success" ? <CheckCircle2 size={14} /> : <AlertCircle size={14} />}
                                        {message.text}
                                    </motion.div>
                                )}

                                <button
                                    type="submit"
                                    disabled={saving}
                                    className="w-full bg-primary text-white py-3.5 rounded-xl font-bold text-sm shadow-lg shadow-primary/20 hover:bg-primary/90 transition-all flex items-center justify-center gap-2 disabled:opacity-50 active:scale-[0.98]"
                                >
                                    {saving ? <Loader2 size={18} className="animate-spin" /> : <Save size={18} />}
                                    {t("profile.save")}
                                </button>
                            </form>
                        </motion.section>
                    </div>

                    {/* Right: Activity Tracker */}
                    <div id="pils" className="lg:col-span-8">
                        <motion.section
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            className="bg-card border border-border rounded-3xl p-8 shadow-xl min-h-[500px]"
                        >
                            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                                <div className="space-y-1">
                                    <h2 className="text-2xl font-black flex items-center gap-3">
                                        <Activity className="text-secondary" size={28} />
                                        {t("profile.my_pils")}
                                    </h2>
                                    <p className="text-sm text-muted-foreground font-medium">Tracking your public interest contributions.</p>
                                </div>
                                <Link
                                    href="/create-pil"
                                    className="flex items-center justify-center gap-2 bg-secondary/10 text-secondary hover:bg-secondary hover:text-white px-5 py-2.5 rounded-xl font-bold text-sm transition-all active:scale-[0.98]"
                                >
                                    <PlusCircle size={18} />
                                    {t("nav.file_pil")}
                                </Link>
                            </div>

                            {myPils.length > 0 ? (
                                <div className="grid grid-cols-1 gap-4">
                                    {myPils.map((pil) => (
                                        <motion.div
                                            key={pil.id}
                                            whileHover={{ x: 5 }}
                                            className="group relative"
                                        >
                                            <Link
                                                href={`/pil/${pil.id}`}
                                                className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-muted/30 hover:bg-muted/50 border border-transparent hover:border-border/50 p-5 rounded-2xl transition-all"
                                            >
                                                <div className="flex-grow space-y-2">
                                                    <div className="flex items-center gap-3">
                                                        <span className={cn(
                                                            "text-[10px] uppercase font-bold px-2 py-0.5 rounded-md",
                                                            pil.status?.toLowerCase() === "accepted" ? "bg-green-100 text-green-700" : "bg-blue-100 text-blue-700"
                                                        )}>
                                                            {pil.status || "Filed"}
                                                        </span>
                                                        <span className="text-xs text-muted-foreground flex items-center gap-1 font-medium">
                                                            <Calendar size={12} />
                                                            {pil.createdAt ? new Date(pil.createdAt.seconds * 1000).toLocaleDateString() : "Draft"}
                                                        </span>
                                                    </div>
                                                    <h3 className="text-lg font-bold group-hover:text-primary transition-colors line-clamp-1">
                                                        {pil.title}
                                                    </h3>
                                                </div>
                                                <div className="flex items-center justify-between md:justify-end gap-6 border-t md:border-t-0 pt-4 md:pt-0 border-border/50">
                                                    <div className="flex items-center gap-2">
                                                        <div className="w-8 h-8 rounded-full bg-secondary/10 flex items-center justify-center text-secondary">
                                                            <ThumbsUp size={14} fill="currentColor" />
                                                        </div>
                                                        <span className="font-bold text-sm">{pil.supporters || 0}</span>
                                                    </div>
                                                    <ChevronRight className="text-muted-foreground group-hover:text-primary transition-all" size={20} />
                                                </div>
                                            </Link>
                                        </motion.div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center py-20 text-center space-y-4">
                                    <div className="w-24 h-24 bg-muted rounded-full flex items-center justify-center text-muted-foreground/30">
                                        <PieChart size={48} />
                                    </div>
                                    <div className="max-w-xs space-y-2">
                                        <h3 className="font-bold text-xl">{t("profile.no_pils")}</h3>
                                        <p className="text-sm text-muted-foreground">Your advocacy journey starts here. File your first petition to see it tracked.</p>
                                    </div>
                                    <Link
                                        href="/create-pil"
                                        className="bg-primary text-white px-8 py-3 rounded-xl font-bold shadow-xl shadow-primary/20 hover:shadow-primary/40 transition-all active:scale-95"
                                    >
                                        {t("nav.file_pil")}
                                    </Link>
                                </div>
                            )}
                        </motion.section>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { db } from "@/lib/firebase";
import { collection, query, orderBy, onSnapshot, limit, getDocs } from "firebase/firestore";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { generateEmbedding, cosineSimilarity } from "@/lib/gemini";
import { GoogleGenerativeAI } from "@google/generative-ai";
import {
    Search,
    Filter,
    TrendingUp,
    Clock,
    Flame,
    ChevronRight,
    ThumbsUp,
    Calendar,
    User as UserIcon,
    SearchX,
    Sparkles,
    Plus,
    MapPin,
    AlertCircle
} from "lucide-react";
import { useLanguage } from "@/context/LanguageContext";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

interface PIL {
    id: string;
    pilId?: string;
    title: string;
    description: string;
    supporters: number;
    createdAt: { seconds: number; nanoseconds: number } | null;
    createdBy: string;
    creatorName?: string;
    status?: string;
    category?: string;
    location?: { state: string; city: string };
    urgency?: string;
    embedding?: number[];
}

interface UnifiedThread {
    id: string;
    title: string;
    description: string;
    pils: PIL[];
}

export default function Tracker() {
    const { t } = useLanguage();
    const { user } = useAuth();
    const [pils, setPils] = useState<PIL[]>([]);
    const [loading, setLoading] = useState(true);
    const [sortBy, setSortBy] = useState("newest");
    const [searchQuery, setSearchQuery] = useState("");
    const [showMyPils, setShowMyPils] = useState(false);
    const [unifiedThreads, setUnifiedThreads] = useState<UnifiedThread[]>([]);
    const [loadingThreads, setLoadingThreads] = useState(false);

    useEffect(() => {
        // Fetch all PILs and sort client-side to avoid complex index requirements for simple demo
        const q = query(collection(db, "pils"), limit(100));
        const unsubscribe = onSnapshot(q, (snapshot) => {
            const pilsData = snapshot.docs.map((doc) => {
                const data = doc.data();
                return {
                    id: doc.id,
                    ...data,
                    supporters: data.supporters || 0,
                    status: data.status || "filed",
                };
            }) as PIL[];
            setPils(pilsData);
            setLoading(false);
            fetchUnifiedThreads(pilsData);
        }, (error) => {
            console.error("Error fetching PILs:", error);
            setLoading(false);
        });

        return () => unsubscribe();
    }, []);

    const fetchUnifiedThreads = async (allPils: PIL[]) => {
        if (allPils.length < 2) return;
        setLoadingThreads(true);
        try {
            // Group semantically related PILs using embeddings
            const threads: UnifiedThread[] = [];
            const visited = new Set<string>();

            for (let i = 0; i < allPils.length; i++) {
                if (visited.has(allPils[i].id) || !allPils[i].embedding) continue;

                const currentGroup = [allPils[i]];
                visited.add(allPils[i].id);

                for (let j = i + 1; j < allPils.length; j++) {
                    if (visited.has(allPils[j].id) || !allPils[j].embedding) continue;

                    const similarity = cosineSimilarity(allPils[i].embedding!, allPils[j].embedding!);
                    if (similarity > 0.75) {
                        currentGroup.push(allPils[j]);
                        visited.add(allPils[j].id);
                    }
                }

                if (currentGroup.length > 1) {
                    // Use Gemini to generate a unified title/summary if we had more time/keys, 
                    // for now use a smart heuristic or simple prompt
                    threads.push({
                        id: `thread-${allPils[i].id}`,
                        title: `Unified Issue: ${currentGroup[0].title} & Others`,
                        description: `This thread combines ${currentGroup.length} related petitions concerning similar legal issues to help courts address them collectively.`,
                        pils: currentGroup
                    });
                }
            }
            setUnifiedThreads(threads);
        } catch (error) {
            console.error("Error generating unified threads:", error);
        } finally {
            setLoadingThreads(false);
        }
    };

    const filteredPils = pils
        .filter(pil => {
            const matchesSearch = pil.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
                pil.description.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesUser = showMyPils ? (user && pil.createdBy === user.uid) : true;
            return matchesSearch && matchesUser;
        })
        .sort((a, b) => {
            if (sortBy === "trending") {
                return b.supporters - a.supporters;
            } else if (sortBy === "hot") {
                // Hot = High support + Recent
                const scoreA = (a.supporters * 1.5) + (a.createdAt?.seconds || 0) / 100000;
                const scoreB = (b.supporters * 1.5) + (b.createdAt?.seconds || 0) / 100000;
                return scoreB - scoreA;
            } else {
                // Newest
                return (b.createdAt?.seconds || 0) - (a.createdAt?.seconds || 0);
            }
        });

    const sortTabs = [
        { id: "trending", label: t("tracker.trending"), icon: TrendingUp },
        { id: "hot", label: t("tracker.hot"), icon: Flame },
        { id: "newest", label: t("tracker.newest"), icon: Clock },
    ];

    const getStatusStyles = (status: string) => {
        const s = status?.toLowerCase() || "awaiting consensus";
        switch (s) {
            case "hearing": return "bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400";
            case "accepted": return "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400";
            case "scrutiny": return "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400";
            case "heard": return "bg-blue-600 text-white dark:bg-blue-800 dark:text-white";
            case "ready for review": return "bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-400";
            case "awaiting consensus": return "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400";
            default: return "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400";
        }
    };

    return (
        <div className="min-h-screen bg-background">
            {/* Header & Search */}
            <div className="bg-muted/30 border-b border-border py-12">
                <div className="container mx-auto px-4">
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                        <div className="space-y-2">
                            <h1 className="text-3xl md:text-4xl font-bold tracking-tight">{t("tracker.title")}</h1>
                            <p className="text-muted-foreground text-lg">
                                {t("tracker.description")}
                            </p>
                        </div>
                        <div className="relative max-w-md w-full">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" size={20} />
                            <input
                                type="text"
                                placeholder={t("tracker.search_placeholder")}
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-10 pr-4 py-3 bg-background border border-border rounded-xl focus:ring-2 focus:ring-primary/20 focus:border-primary outline-none transition-all"
                            />
                        </div>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 py-8">
                {/* Filters & Tabs */}
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mb-8">
                    <div className="flex items-center gap-4 w-full sm:w-auto">
                        <div className="flex bg-muted p-1 rounded-xl">
                            {sortTabs.map((tab) => (
                                <button
                                    key={tab.id}
                                    onClick={() => setSortBy(tab.id)}
                                    className={cn(
                                        "flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-semibold transition-all",
                                        sortBy === tab.id
                                            ? "bg-background text-primary shadow-sm"
                                            : "text-muted-foreground hover:text-foreground"
                                    )}
                                >
                                    <tab.icon size={16} />
                                    {tab.label}
                                </button>
                            ))}
                        </div>
                        {user && (
                            <button
                                onClick={() => setShowMyPils(!showMyPils)}
                                className={cn(
                                    "px-4 py-2 rounded-xl text-sm font-bold border transition-all",
                                    showMyPils
                                        ? "bg-primary text-white border-primary"
                                        : "bg-background text-muted-foreground border-border hover:border-primary/50"
                                )}
                            >
                                {showMyPils ? "All PILs" : "My PILs"}
                            </button>
                        )}
                    </div>

                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <Filter size={16} />
                        <span>{t("tracker.showing_count")} {filteredPils.length}</span>
                    </div>
                </div>

                {/* Unified Threads Section */}
                {unifiedThreads.length > 0 && !showMyPils && (
                    <div className="mb-12">
                        <div className="flex items-center justify-between mb-6">
                            <div className="flex items-center gap-3">
                                <div className="bg-primary/10 p-2 rounded-lg text-primary">
                                    <Sparkles size={20} />
                                </div>
                                <h2 className="text-xl font-bold">Smart Unified Issue Threads</h2>
                                <span className="text-xs bg-muted px-2 py-1 rounded-full text-muted-foreground font-medium">AI-Consolidated</span>
                            </div>
                            <Link href="/unified" className="flex items-center gap-1 text-sm font-bold text-primary hover:underline">
                                View All Threads →
                            </Link>
                        </div>
                        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                            {unifiedThreads.map((thread) => (
                                <div key={thread.id} className="bg-gradient-to-br from-primary/5 to-secondary/5 border border-primary/20 rounded-3xl p-6 shadow-sm">
                                    <div className="flex items-center gap-2 mb-4">
                                        <div className="flex -space-x-2">
                                            {thread.pils.slice(0, 3).map((p, idx) => (
                                                <div key={idx} className="w-8 h-8 rounded-full border-2 border-background bg-primary/10 flex items-center justify-center text-[10px] font-bold">
                                                    {p.creatorName?.[0] || "A"}
                                                </div>
                                            ))}
                                        </div>
                                        <span className="text-xs font-bold text-primary">{thread.pils.length} Related Petitions</span>
                                    </div>
                                    <h3 className="text-lg font-bold mb-2">{thread.title}</h3>
                                    <p className="text-sm text-muted-foreground mb-6 leading-relaxed">
                                        {thread.description}
                                    </p>
                                    <div className="flex flex-wrap gap-2">
                                        {thread.pils.map((p) => (
                                            <Link
                                                key={p.id}
                                                href={`/pil/${p.id}`}
                                                className="text-[10px] bg-background border border-border px-3 py-1.5 rounded-full hover:border-primary transition-colors flex items-center gap-1.5 font-medium"
                                            >
                                                {p.pilId || "PIL-..."}
                                            </Link>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Grid */}
                {loading ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {[1, 2, 3, 4, 5, 6].map((i) => (
                            <div key={i} className="h-64 bg-muted animate-pulse rounded-2xl border" />
                        ))}
                    </div>
                ) : filteredPils.length > 0 ? (
                    <motion.div
                        layout
                        className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
                    >
                        <AnimatePresence mode="popLayout">
                            {filteredPils.map((pil) => (
                                <motion.div
                                    key={pil.id}
                                    layout
                                    initial={{ opacity: 0, scale: 0.95 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    exit={{ opacity: 0, scale: 0.95 }}
                                    className="group relative flex flex-col bg-card border border-border rounded-2xl overflow-hidden hover:shadow-xl hover:border-primary/20 transition-all"
                                >
                                    <div className="p-6 flex-grow">
                                        <div className="flex items-center justify-between mb-4">
                                            <span className={cn(
                                                "text-[10px] uppercase tracking-widest font-bold px-2 py-1 rounded-md",
                                                getStatusStyles(pil.status || "Awaiting Consensus")
                                            )}>
                                                {pil.status || "Awaiting Consensus"}
                                            </span>
                                            <span className="text-xs font-black text-primary/40 uppercase tracking-tighter">
                                                {pil.pilId || `PIL-${pil.id.substring(0, 6).toUpperCase()}`}
                                            </span>
                                            <span className="text-xs text-muted-foreground flex items-center gap-1 font-medium">
                                                <Calendar size={12} />
                                                {pil.createdAt ? new Date(pil.createdAt.seconds * 1000).toLocaleDateString() : "Pending"}
                                            </span>
                                        </div>

                                        <h3 className="text-xl font-bold mb-2 group-hover:text-primary transition-colors line-clamp-2">
                                            {pil.title}
                                        </h3>

                                        <div className="flex flex-wrap items-center gap-2 mb-3 text-xs text-muted-foreground">
                                            <span className="bg-primary/10 text-primary px-2 py-0.5 rounded-full font-medium flex items-center gap-1">
                                                <Filter size={10} />
                                                {pil.category || "Social Welfare"}
                                            </span>
                                            <span className="flex items-center gap-1 bg-muted px-2 py-0.5 rounded-full font-medium">
                                                <MapPin size={10} />
                                                {(pil.location?.city) ? `${pil.location.city}, ${pil.location.state}` : "New Delhi, Delhi"}
                                            </span>
                                            <span className={cn(
                                                "flex items-center gap-1 px-2 py-0.5 rounded-full font-bold",
                                                (pil.urgency === "Critical" || pil.urgency === "High") ? "bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-400" : "bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-400"
                                            )}>
                                                <Flame size={10} />
                                                {pil.urgency || "Medium"}
                                            </span>
                                        </div>

                                        <p className="text-muted-foreground text-sm leading-relaxed mb-6 line-clamp-3">
                                            {pil.description}
                                        </p>

                                        <div className="flex items-center gap-3 mt-auto">
                                            <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center text-primary">
                                                <UserIcon size={14} />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-xs font-bold">{pil.creatorName || "Anonymous Voter"}</span>
                                                <span className="text-[10px] text-muted-foreground">Citizen Petitioner</span>
                                            </div>
                                        </div>
                                    </div>

                                    <div className="p-4 bg-muted/30 border-t border-border flex items-center justify-between">
                                        <div className="flex items-center gap-2 font-bold text-sm">
                                            <div className="bg-secondary/10 text-secondary p-1.5 rounded-lg">
                                                <ThumbsUp size={14} fill="currentColor" />
                                            </div>
                                            {pil.supporters || 0}
                                        </div>
                                        <Link
                                            href={`/pil/${pil.id}`}
                                            className="flex items-center gap-1 text-sm font-bold text-primary hover:underline group/link"
                                        >
                                            {t("tracker.view_details")}
                                            <ChevronRight size={16} className="group-hover/link:translate-x-1 transition-transform" />
                                        </Link>
                                    </div>
                                </motion.div>
                            ))}
                        </AnimatePresence>
                    </motion.div>
                ) : (
                    <div className="text-center py-20 bg-muted/20 rounded-3xl border border-dashed flex flex-col items-center gap-4">
                        <div className="w-16 h-16 bg-muted rounded-full flex items-center justify-center text-muted-foreground">
                            <SearchX size={32} />
                        </div>
                        <div className="space-y-1">
                            <h3 className="text-xl font-bold">{t("tracker.no_results")}</h3>
                            <p className="text-muted-foreground">Try adjusting your search or filters to find what you&apos;re looking for.</p>
                        </div>
                        <Link
                            href="/create-pil"
                            className="mt-4 flex items-center gap-2 bg-primary text-white px-6 py-2 rounded-xl font-bold"
                        >
                            <Plus size={20} />
                            {t("tracker.start_petition")}
                        </Link>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { db } from "@/lib/firebase";
import { collection, getDocs, query, limit, addDoc, serverTimestamp, doc, setDoc } from "firebase/firestore";
import { generateEmbedding, cosineSimilarity } from "@/lib/gemini";
import { GoogleGenerativeAI } from "@google/generative-ai";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import { Layers, Sparkles, RefreshCw, ExternalLink, ArrowLeft, Hash, Users, ChevronRight } from "lucide-react";

interface PIL {
    id: string;
    title: string;
    description: string;
    embedding?: number[];
    supporters: number;
    status: string;
    pilId?: string;
}

interface Thread {
    id: string;
    pilIds: string[];
    pils: PIL[];
    summary: string;
    issueTitle: string;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    createdAt?: any;
}

export default function UnifiedPage() {
    const [threads, setThreads] = useState<Thread[]>([]);
    const [loading, setLoading] = useState(true);
    const [consolidating, setConsolidating] = useState(false);
    const [pils, setPils] = useState<PIL[]>([]);

    // Fetch existing threads and PILs
    useEffect(() => {
        fetchData();
    }, []);

    async function fetchData() {
        setLoading(true);
        try {
            // Fetch threads
            const threadsSnap = await getDocs(collection(db, "threads"));
            const fetchedThreads: Thread[] = [];

            // Fetch all PILs for reference
            const pilsSnap = await getDocs(query(collection(db, "pils"), limit(50)));
            const allPils: PIL[] = pilsSnap.docs.map(d => ({ id: d.id, ...d.data() } as PIL));
            setPils(allPils);

            for (const tDoc of threadsSnap.docs) {
                const data = tDoc.data();
                const threadPils = allPils.filter(p => data.pilIds?.includes(p.id));
                fetchedThreads.push({
                    id: tDoc.id,
                    pilIds: data.pilIds || [],
                    pils: threadPils,
                    summary: data.summary || "",
                    issueTitle: data.issueTitle || "Untitled Thread",
                    createdAt: data.createdAt
                });
            }

            setThreads(fetchedThreads);
        } catch (error) {
            console.error("Error fetching data:", error);
        } finally {
            setLoading(false);
        }
    }

    async function runConsolidation() {
        setConsolidating(true);
        try {
            // Fetch all PILs
            const pilsSnap = await getDocs(query(collection(db, "pils"), limit(50)));
            const allPils: PIL[] = pilsSnap.docs.map(d => ({ id: d.id, ...d.data() } as PIL));

            // Generate embeddings for PILs that don't have them
            const pilsWithEmbeddings: (PIL & { embedding: number[] })[] = [];

            for (const pil of allPils) {
                let emb = pil.embedding;
                if (!emb && pil.description) {
                    try {
                        emb = await generateEmbedding(pil.description);
                    } catch { continue; }
                }
                if (emb) {
                    pilsWithEmbeddings.push({ ...pil, embedding: emb });
                }
            }

            // Pairwise cosine similarity clustering
            const THRESHOLD = 0.75;
            const used = new Set<string>();
            const groups: PIL[][] = [];

            for (let i = 0; i < pilsWithEmbeddings.length; i++) {
                if (used.has(pilsWithEmbeddings[i].id)) continue;

                const group: PIL[] = [pilsWithEmbeddings[i]];
                used.add(pilsWithEmbeddings[i].id);

                for (let j = i + 1; j < pilsWithEmbeddings.length; j++) {
                    if (used.has(pilsWithEmbeddings[j].id)) continue;

                    const sim = cosineSimilarity(pilsWithEmbeddings[i].embedding, pilsWithEmbeddings[j].embedding);
                    if (sim > THRESHOLD) {
                        group.push(pilsWithEmbeddings[j]);
                        used.add(pilsWithEmbeddings[j].id);
                    }
                }

                if (group.length >= 2) {
                    groups.push(group);
                }
            }

            // Generate summaries and save to Firestore
            const genAI = new GoogleGenerativeAI(process.env.NEXT_PUBLIC_GEMINI_API_KEY || "");
            const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash" });

            const newThreads: Thread[] = [];

            for (const group of groups) {
                const textsJoined = group.map((p, i) => `PIL ${i + 1}: "${p.title}" - ${p.description?.substring(0, 200)}`).join("\n\n");

                let summary = "";
                let issueTitle = "";

                try {
                    const result = await model.generateContent(
                        `You are consolidating related Public Interest Litigations for court filing in India.
                        
Given these related PIL petitions:
${textsJoined}

Respond in this EXACT JSON format (no markdown, just raw JSON):
{
  "issueTitle": "A short unified title for this group of issues (max 10 words)",
  "summary": "A 2-3 sentence cohesive issue statement summarizing all related PILs for a unified court filing"
}`
                    );
                    const text = result.response.text().replace(/```json|```/g, "").trim();
                    const parsed = JSON.parse(text);
                    summary = parsed.summary;
                    issueTitle = parsed.issueTitle;
                } catch {
                    issueTitle = `Related Issues: ${group[0].title}`;
                    summary = `${group.length} related petitions addressing similar concerns.`;
                }

                const threadData = {
                    pilIds: group.map(p => p.id),
                    summary,
                    issueTitle,
                    createdAt: serverTimestamp(),
                    pilCount: group.length,
                    totalSupporters: group.reduce((sum, p) => sum + (p.supporters || 0), 0)
                };

                const threadRef = await addDoc(collection(db, "threads"), threadData);

                newThreads.push({
                    id: threadRef.id,
                    ...threadData,
                    pils: group
                });
            }

            setThreads(newThreads);
            setPils(allPils);
        } catch (error) {
            console.error("Error consolidating:", error);
        } finally {
            setConsolidating(false);
        }
    }

    return (
        <div className="min-h-screen bg-muted/30">
            {/* Header */}
            <div className="bg-background border-b border-border py-4 sticky top-[65px] z-30">
                <div className="container mx-auto px-4 flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <Link href="/tracker" className="p-2 hover:bg-muted rounded-full transition-colors">
                            <ArrowLeft size={24} />
                        </Link>
                        <div>
                            <h1 className="text-xl font-bold tracking-tight flex items-center gap-2">
                                <Layers size={22} className="text-primary" />
                                Unified Issue Threads
                            </h1>
                            <p className="text-xs text-muted-foreground">AI-consolidated petitions for court filing</p>
                        </div>
                    </div>
                    <button
                        onClick={runConsolidation}
                        disabled={consolidating}
                        className="flex items-center gap-2 bg-primary text-white px-5 py-2.5 rounded-xl font-bold text-sm shadow-lg hover:bg-primary/90 transition-all disabled:opacity-50"
                    >
                        {consolidating ? (
                            <>
                                <div className="w-4 h-4 border-2 border-white border-t-transparent animate-spin rounded-full" />
                                Consolidating...
                            </>
                        ) : (
                            <>
                                <RefreshCw size={16} />
                                Run Consolidation
                            </>
                        )}
                    </button>
                </div>
            </div>

            <div className="container mx-auto px-4 py-10 max-w-5xl">
                {/* Stats Cards */}
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-10">
                    <div className="bg-card border border-border rounded-2xl p-5 shadow-sm">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Total PILs</p>
                                <p className="text-3xl font-black text-primary">{pils.length}</p>
                            </div>
                            <Hash size={28} className="text-primary/20" />
                        </div>
                    </div>
                    <div className="bg-card border border-border rounded-2xl p-5 shadow-sm">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">Unified Threads</p>
                                <p className="text-3xl font-black text-secondary">{threads.length}</p>
                            </div>
                            <Layers size={28} className="text-secondary/20" />
                        </div>
                    </div>
                    <div className="bg-card border border-border rounded-2xl p-5 shadow-sm">
                        <div className="flex items-center justify-between">
                            <div>
                                <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider">PILs Grouped</p>
                                <p className="text-3xl font-black text-green-600">
                                    {threads.reduce((sum, t) => sum + t.pilIds.length, 0)}
                                </p>
                            </div>
                            <Users size={28} className="text-green-600/20" />
                        </div>
                    </div>
                </div>

                {/* Loading State */}
                {loading ? (
                    <div className="flex flex-col items-center justify-center py-20">
                        <div className="w-8 h-8 border-3 border-primary border-t-transparent animate-spin rounded-full mb-4" />
                        <p className="text-muted-foreground font-medium">Loading threads...</p>
                    </div>
                ) : threads.length === 0 ? (
                    <div className="text-center py-20 space-y-6">
                        <div className="w-20 h-20 bg-primary/10 rounded-3xl flex items-center justify-center mx-auto">
                            <Sparkles size={40} className="text-primary" />
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold mb-2">No Threads Yet</h2>
                            <p className="text-muted-foreground max-w-md mx-auto">
                                Click &quot;Run Consolidation&quot; to use AI to group similar petitions into unified issue threads for court filing.
                            </p>
                        </div>
                    </div>
                ) : (
                    <div className="space-y-6">
                        <AnimatePresence>
                            {threads.map((thread, idx) => (
                                <motion.div
                                    key={thread.id}
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    transition={{ delay: idx * 0.1 }}
                                    className="bg-card border border-border rounded-2xl shadow-sm overflow-hidden hover:shadow-lg transition-shadow"
                                >
                                    {/* Thread Header */}
                                    <div className="bg-gradient-to-r from-primary/5 to-secondary/5 p-6 border-b border-border">
                                        <div className="flex items-start justify-between gap-4">
                                            <div className="flex-1">
                                                <div className="flex items-center gap-2 mb-2">
                                                    <span className="bg-primary/10 text-primary text-[10px] font-black uppercase tracking-wider px-2 py-0.5 rounded-full">
                                                        Thread #{idx + 1}
                                                    </span>
                                                    <span className="bg-green-100 text-green-700 text-[10px] font-black uppercase tracking-wider px-2 py-0.5 rounded-full">
                                                        {thread.pilIds.length} PILs Consolidated
                                                    </span>
                                                </div>
                                                <h3 className="text-xl font-bold tracking-tight">{thread.issueTitle}</h3>
                                            </div>
                                            <div className="bg-primary/10 p-2.5 rounded-xl">
                                                <Layers size={22} className="text-primary" />
                                            </div>
                                        </div>
                                    </div>

                                    {/* AI Summary */}
                                    <div className="p-6 border-b border-border">
                                        <div className="flex items-center gap-2 mb-3">
                                            <Sparkles size={14} className="text-primary" />
                                            <span className="text-xs font-bold text-muted-foreground uppercase tracking-wider">AI-Generated Unified Summary</span>
                                        </div>
                                        <p className="text-sm leading-relaxed text-muted-foreground">{thread.summary}</p>
                                    </div>

                                    {/* Linked PILs */}
                                    <div className="p-6">
                                        <p className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-4">Linked Petitions</p>
                                        <div className="space-y-2">
                                            {thread.pils.map((pil) => (
                                                <Link
                                                    key={pil.id}
                                                    href={`/pil/${pil.id}`}
                                                    className="flex items-center justify-between p-3 bg-muted/50 rounded-xl border border-border hover:border-primary/30 transition-all group"
                                                >
